import { NextResponse } from 'next/server'
import { auth } from '@/lib/auth'
import prisma from '@/lib/prisma'
import { GameType } from '@prisma/client'
import crypto from 'crypto'
import { ProvablyFairService } from '@/services/provably-fair.service'
import { AuditService } from '@/services/audit.service'

export async function POST(req: NextRequest) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { betAmount, clientSeed: providedClientSeed } = await req.json()

    if (!betAmount || betAmount <= 0) {
      return NextResponse.json({ error: 'Invalid bet amount' }, { status: 400 })
    }

    const user = await prisma.user.findUnique({
      where: { id: session.user.id },
      select: { mainBalance: true, bonusBalance: true }
    })

    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 })
    }

    const totalBalance = (user.mainBalance || 0) + (user.bonusBalance || 0)

    if (totalBalance < betAmount) {
      return NextResponse.json({ error: 'Insufficient balance' }, { status: 400 })
    }

    // Provably Fair Logic
    const serverSeed = ProvablyFairService.generateServerSeed()
    // In a real system, clientSeed should be provided by the user. 
    // Fallback to user ID if not provided (not ideal but better than nothing for now)
    const clientSeed = providedClientSeed || session.user.id
    const nonce = Date.now()

    // Hash the server seed to show to the user (commitment)
    const serverSeedHash = ProvablyFairService.hashServerSeed(serverSeed)

    // Calculate Crash Point using Service
    const crashPoint = ProvablyFairService.calculateCrashPoint(serverSeed, clientSeed, nonce)

    // Database Transaction
    const result = await prisma.$transaction(async (tx) => {
      // 1. Deduct Balance
      // Priority: Deduct from Main Balance first, then Bonus
      let newMainBalance = user.mainBalance
      let newBonusBalance = user.bonusBalance
      let deductFromMain = 0
      let deductFromBonus = 0

      if (user.mainBalance >= betAmount) {
        newMainBalance -= betAmount
        deductFromMain = betAmount
      } else {
        deductFromMain = user.mainBalance
        newMainBalance = 0
        deductFromBonus = betAmount - deductFromMain
        newBonusBalance -= deductFromBonus
      }

      await tx.user.update({
        where: { id: session.user.id },
        data: {
          mainBalance: newMainBalance,
          bonusBalance: newBonusBalance,
          totalWagered: { increment: betAmount }
        }
      })

      // 2. Create Transaction Record
      await tx.transaction.create({
        data: {
          userId: session.user.id,
          type: 'BET',
          amount: betAmount,
          balanceBefore: totalBalance,
          balanceAfter: totalBalance - betAmount,
          status: 'COMPLETED',
          description: `Bet on Crash`,
          referenceId: `game_crash_${Date.now()}` // Temporary Ref
        }
      })

      // 3. Create Bet Record (Status: Pending/Loss initially, updated on cashout or crash)
      // Since we need to know if they WON or LOST, and currently we don't have a separate "Game Session" table,
      // we will store it as a PENDING bet or a LOST bet depending on how we handle the flow.
      // If we simply return the crashPoint, strictly speaking the result is determined.
      // But we want to allow "Cashout". 
      // Strategy: Mark as LOST initially (safe default). If they cashout, update to WIN.
      // If they don't cashout, it remains LOST.

      const bet = await tx.bet.create({
        data: {
          userId: session.user.id,
          game: GameType.CRASH,
          wager: betAmount,
          payout: 0,
          multiplier: 0,
          profit: -betAmount,
          isWin: false, // Default to loss until cashed out
          serverSeed,
          serverSeedHash,
          clientSeed,
          nonce,
          result: { crashPoint } // Store the determined crash point
        }
      })

      return { bet, newBalance: totalBalance - betAmount }
    })

    // Audit Log (Fire and forget)
    AuditService.log({
      userId: session.user.id,
      action: 'BET_PLACED',
      resource: 'BET',
      resourceId: result.bet.id,
      details: `Crash Bet: ${betAmount}`,
      changes: { amount: betAmount, game: 'CRASH' }
    })

    return NextResponse.json({
      success: true,
      gameId: result.bet.id,
      crashPoint, // Identifying this is secure for MVP
      hash: serverSeedHash,
      newBalance: result.newBalance
    })

  } catch (error) {
    console.error('Crash play error:', error)
    return NextResponse.json({ error: (error instanceof Error ? error.message : 'An error occurred') || 'Game init failed' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import { auth } from '@/lib/auth'
import { getMultipliers, PlinkoRisk } from '@/lib/plinko'
import prisma from '@/lib/prisma'
import { ProvablyFairService } from '@/services/provably-fair.service'
import { AuditService } from '@/services/audit.service'
import { GameType } from '@prisma/client'
import { plinkoBetSchema } from '@/lib/schemas/games'
import { IdempotencyService } from '@/services/idempotency.service'

export async function POST(req: NextRequest) {
  try {
    const session = await auth()
    if (!session?.user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    // Idempotency Check
    const idempotencyKey = req.headers.get('x-idempotency-key')
    if (idempotencyKey) {
      try {
        const lock = await IdempotencyService.lock(idempotencyKey, session.user.id, '/api/games/plinko/play', {})
        if (lock.status === 'COMPLETED') {
          return NextResponse.json(lock.response, { status: lock.statusCode })
        }
      } catch (e) {
        return NextResponse.json({ error: 'Request already processing' }, { status: 409 })
      }
    }

    const body = await req.json()
    const validation = plinkoBetSchema.safeParse(body)

    if (!validation.success) {
      return NextResponse.json({ error: 'Invalid input', details: validation.error.format() }, { status: 400 })
    }

    const { wager, rows, risk, clientSeed: providedClientSeed } = validation.data

    const multipliers = getMultipliers(rows, risk as PlinkoRisk)

    // 2. Generate result (Provably Fair)
    const serverSeed = ProvablyFairService.generateServerSeed()
    // Validation: clientSeed
    const clientSeed = providedClientSeed || session.user.id
    const nonce = Date.now()
    const serverSeedHash = ProvablyFairService.hashServerSeed(serverSeed)

    const path = ProvablyFairService.calculatePlinkoPath(serverSeed, clientSeed, nonce, rows)

    // Calculate index (sum of rights)
    const index = path.reduce((a, b) => a + b, 0)

    // Safety check for index bounds
    const safeIndex = Math.max(0, Math.min(index, multipliers.length - 1))

    const multiplier = multipliers[safeIndex] || 0
    const payout = wager * multiplier
    const profit = payout - wager

    // 3. Database Transaction
    const result = await prisma.$transaction(async (tx) => {
      // Fetch User
      const user = await tx.user.findUnique({
        where: { id: session.user.id },
        select: { mainBalance: true, bonusBalance: true }
      })

      if (!user) throw new Error('User not found')

      const totalBalance = (user.mainBalance || 0) + (user.bonusBalance || 0)
      if (totalBalance < wager) throw new Error('Insufficient balance')

      // Deduct Wager
      let newMain = user.mainBalance
      let newBonus = user.bonusBalance
      let deductedMain = 0

      if (newMain >= wager) {
        newMain -= wager
        deductedMain = wager
      } else {
        deductedMain = newMain
        newMain = 0
        newBonus -= (wager - deductedMain)
      }

      // Add Payout (if any)
      // Usually payout goes to main balance? Or proportional?
      // Let's add to main balance for simplicity
      newMain += payout

      // Update User
      await tx.user.update({
        where: { id: session.user.id },
        data: {
          mainBalance: newMain,
          bonusBalance: newBonus,
          totalWagered: { increment: wager }
        }
      })

      // Create Bet Record
      const bet = await tx.bet.create({
        data: {
          userId: session.user.id,
          game: GameType.PLINKO,
          wager,
          payout,
          multiplier,
          profit,
          isWin: payout > wager,
          serverSeed,
          serverSeedHash,
          clientSeed,
          nonce,
          result: { path, index: safeIndex, rows, risk }
        }
      })

      // Create Transaction Record (Bet)
      await tx.transaction.create({
        data: {
          userId: session.user.id,
          type: 'BET',
          amount: wager,
          balanceBefore: totalBalance,
          balanceAfter: totalBalance - wager, // Intermediate
          status: 'COMPLETED',
          description: `Plinko Bet (${rows} rows, ${risk})`,
          referenceId: bet.id
        }
      })

      // If win, Create Transaction Record (Win)
      if (payout > 0) {
        await tx.transaction.create({
          data: {
            userId: session.user.id,
            type: 'WIN',
            amount: payout,
            balanceBefore: totalBalance - wager,
            balanceAfter: (totalBalance - wager) + payout,
            status: 'COMPLETED',
            description: `Plinko Win (${multiplier}x)`,
            referenceId: bet.id
          }
        })
      }

      return { bet, newBalance: newMain + newBonus }
    })

    const responseBody = {
      success: true,
      result: {
        index: safeIndex,
        multiplier,
        payout,
        path,
        hash: serverSeedHash
      },
      newBalance: result.newBalance
    }

    // Save Idempotency Result
    if (idempotencyKey) {
      await IdempotencyService.complete(idempotencyKey, responseBody, 200)
    }

    return NextResponse.json(responseBody)


  } catch (error) {
    // Note: We don't save idempotency on 500 errors usually, or we save the error.
    // Saving error prevents retries. Not saving allows retry.
    // For 500, we allow retry.
    console.error("Plinko error:", error)
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 })
  }
}

