"use client"

import { useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card"
import { useBalance } from "@/context/BalanceContext"
import { createDeck, shuffleDeck, type Card as CardType, getCardColor, getSuitSymbol } from "@/lib/deck"
import { ShieldCheck } from "lucide-react"

export default function Blackjack() {
  const { balance, updateBalance } = useBalance()
  // Initialize deck lazily
  const [deck, setDeck] = useState<CardType[]>(() => shuffleDeck(createDeck()))
  const [betAmount, setBetAmount] = useState<number>(10)
  const [playerHand, setPlayerHand] = useState<CardType[]>([])
  const [dealerHand, setDealerHand] = useState<CardType[]>([])
  const [gameState, setGameState] = useState<"betting" | "playing" | "dealerTurn" | "gameOver">("betting")
  const [message, setMessage] = useState("")
  const [outcome, setOutcome] = useState<"win" | "lose" | "push" | null>(null)

  // Initialize deck

  const calculateHandValue = (hand: CardType[]) => {
    let value = 0
    let aces = 0
    hand.forEach(card => {
      value += card.value
      if (card.rank === 'A') aces += 1
    })
    while (value > 21 && aces > 0) {
      value -= 10
      aces -= 1
    }
    return value
  }

  const dealCard = (target: "player" | "dealer", currentDeck: CardType[] = deck) => {
    if (currentDeck.length === 0) return { card: null, newDeck: currentDeck }
    const newDeck = [...currentDeck]
    const card = newDeck.pop()!
    if (target === "player") setPlayerHand(prev => [...prev, card])
    if (target === "dealer") setDealerHand(prev => [...prev, card])
    setDeck(newDeck)
    return { card, newDeck }
  }

  const startGame = () => {
    if (betAmount > balance) return setMessage("Insufficient balance")
    if (isNaN(betAmount) || betAmount <= 0) return setMessage("Invalid bet")

    updateBalance(-betAmount)
    setGameState("playing")
    setMessage("")
    setOutcome(null)
    setPlayerHand([])
    setDealerHand([])

    const currentDeck = shuffleDeck(createDeck())
    // Deal initial cards: P, D, P, D
    const p1 = currentDeck.pop()!
    const d1 = currentDeck.pop()!
    const p2 = currentDeck.pop()!
    const d2 = currentDeck.pop()!

    setPlayerHand([p1, p2])
    setDealerHand([d1, d2])
    setDeck(currentDeck)

    // Check blackjack immediately
    const pValue = calculateHandValue([p1, p2])
    if (pValue === 21) {
       handleGameOver("blackjack", [d1, d2])
    }
  }

  const hit = () => {
    const { card, newDeck: _newDeck } = dealCard("player")
    if (!card) return
    
    // Check bust
    const newValue = calculateHandValue([...playerHand, card])
    if (newValue > 21) {
      setGameState("gameOver")
      setOutcome("lose")
      setMessage("Bust! You lose.")
    }
  }

  const stand = () => {
    setGameState("dealerTurn")
    // Dealer plays logic
    let currentDealerHand = [...dealerHand]
    const currentDeck = [...deck]
    let dValue = calculateHandValue(currentDealerHand)

    const playDealer = async () => {
      while (dValue < 17) {
        await new Promise(r => setTimeout(r, 800)) // Delay for suspense
        const card = currentDeck.pop()!
        currentDealerHand = [...currentDealerHand, card]
        setDealerHand([...currentDealerHand])
        setDeck([...currentDeck])
        dValue = calculateHandValue(currentDealerHand)
      }
      handleGameOver("stand", currentDealerHand)
    }
    playDealer()
  }

  const handleGameOver = (trigger: "blackjack" | "stand", finalDealerHand: CardType[]) => {
    const pValue = calculateHandValue(playerHand)
    const dValue = calculateHandValue(finalDealerHand)

    setGameState("gameOver")

    if (trigger === "blackjack") {
        if (dValue === 21) {
             setOutcome("push")
             updateBalance(betAmount)
             setMessage("Push! Both have Blackjack.")
        } else {
            setOutcome("win")
            updateBalance(betAmount * 2.5) // 3:2 payout
            setMessage("Blackjack! You win 3:2 payout.")
        }
        return
    }

    if (dValue > 21) {
      setOutcome("win")
      updateBalance(betAmount * 2)
      setMessage("Dealer busts! You win.")
    } else if (pValue > dValue) {
      setOutcome("win")
      updateBalance(betAmount * 2)
      setMessage("You win!")
    } else if (pValue < dValue) {
      setOutcome("lose")
      setMessage("Dealer wins.")
    } else {
      setOutcome("push")
      updateBalance(betAmount)
      setMessage("Push!")
    }
  }

  return (
    <div className="flex flex-col items-center justify-center p-4">
      <Card className="w-full max-w-2xl glass-card border-white/10 bg-black/40">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-2xl text-green-400">
            <ShieldCheck className="h-6 w-6" /> Blackjack
          </CardTitle>
          <CardDescription className="text-gray-400">Beat the dealer to 21. Dealer stands on 17.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-8 min-h-[400px] flex flex-col justify-between">
          
          {/* Dealer Area */}
          <div className="flex flex-col items-center gap-4">
            <h3 className="text-sm font-bold uppercase tracking-widest text-gray-500">Dealer</h3>
            <div className="flex gap-2 h-32">
              {dealerHand.map((card, i) => (
                <PlayingCard 
                    key={i} 
                    card={card} 
                    hidden={gameState !== "gameOver" && gameState !== "dealerTurn" && i === 1} 
                />
              ))}
              {dealerHand.length === 0 && <div className="w-24 h-36 rounded-lg border-2 border-dashed border-white/10 bg-white/5" />}
            </div>
            {gameState !== "betting" && gameState !== "playing" && (
                 <div className="text-xl font-bold text-white">{calculateHandValue(dealerHand)}</div>
            )}
          </div>

          {/* Message Area */}
          <div className="h-16 flex items-center justify-center">
             <AnimatePresence>
                {message && (
                    <motion.div 
                        initial={{ scale: 0.8, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        className={`px-6 py-2 rounded-full font-bold text-lg border ${outcome === "win" ? "bg-green-500/20 border-green-500 text-green-400" : outcome === "lose" ? "bg-red-500/20 border-red-500 text-red-400" : "bg-white/10 border-white text-white"}`}
                    >
                        {message}
                    </motion.div>
                )}
             </AnimatePresence>
          </div>

          {/* Player Area */}
          <div className="flex flex-col items-center gap-4">
             <div className="flex gap-2 h-32">
              {playerHand.map((card, i) => (
                <PlayingCard key={i} card={card} />
              ))}
              {playerHand.length === 0 && <div className="w-24 h-36 rounded-lg border-2 border-dashed border-white/10 bg-white/5" />}
            </div>
            {gameState !== "betting" && (
                 <div className="text-xl font-bold text-white">{calculateHandValue(playerHand)}</div>
            )}
             <h3 className="text-sm font-bold uppercase tracking-widest text-gray-500">You</h3>
          </div>

        </CardContent>
        <CardFooter className="flex flex-col gap-4">
            {gameState === "betting" ? (
                 <div className="flex w-full gap-4 items-end">
                     <div className="space-y-2 flex-1">
                        <label className="text-sm font-medium text-gray-400">Bet Amount</label>
                        <Input
                            type="number"
                            value={betAmount}
                            onChange={(e) => setBetAmount(Number(e.target.value))}
                            min={1}
                            className="bg-black/50 border-white/10 focus:border-green-500/50 text-white"
                        />
                    </div>
                    <Button onClick={startGame} className="flex-1 h-10 w-full bg-green-600 hover:bg-green-700 font-bold text-lg">Deal</Button>
                 </div>
            ) : gameState === "playing" ? (
                <div className="flex gap-4 w-full">
                    <Button onClick={hit} variant="secondary" className="flex-1 h-12 text-lg font-bold">Hit</Button>
                    <Button onClick={stand} className="flex-1 h-12 text-lg font-bold bg-green-600 hover:bg-green-700">Stand</Button>
                </div>
            ) : (
                <Button onClick={() => setGameState("betting")} className="w-full h-12 text-lg font-bold bg-white text-black hover:bg-gray-200">Play Again</Button>
            )}
        </CardFooter>
      </Card>
    </div>
  )
}

function PlayingCard({ card, hidden = false }: { card: CardType, hidden?: boolean }) {
    return (
        <motion.div 
            initial={{ scale: 0.5, opacity: 0, rotateY: 180 }}
            animate={{ scale: 1, opacity: 1, rotateY: hidden ? 180 : 0 }}
            transition={{ type: "spring", damping: 15 }}
            className={`
                relative w-24 h-36 rounded-xl border-2 flex items-center justify-center text-3xl font-bold shadow-lg
                ${hidden 
                    ? "bg-linear-to-br from-blue-900 to-black border-blue-800 bg-[url('/card-back.png')] bg-cover" 
                    : "bg-white border-white text-gray-900"}
            `}
            style={{ transformStyle: "preserve-3d" }}
        >
            <div className={`absolute inset-0 backface-hidden flex flex-col items-center justify-center h-full w-full ${hidden ? "hidden" : "block"}`}>
                {!hidden && (
                    <>
                        <div className={`absolute top-2 left-2 text-lg ${getCardColor(card.suit)}`}>{card.rank}</div>
                        <div className={`text-6xl ${getCardColor(card.suit)}`}>{getSuitSymbol(card.suit)}</div>
                        <div className={`absolute bottom-2 right-2 text-lg rotate-180 ${getCardColor(card.suit)}`}>{card.rank}</div>
                    </>
                )}
            </div>
            {/* Back of card (visible when hidden is true due to rotateY) */}
             <div 
                className={`absolute inset-0 backface-hidden w-full h-full rounded-xl bg-linear-to-br from-indigo-600 to-blue-900 flex items-center justify-center border-2 border-indigo-400`}
                style={{ transform: "rotateY(180deg)" }}
            >
                <div className="w-16 h-24 border-2 border-white/20 rounded-lg" />
            </div>
        </motion.div>
    )
}

"use client"

import { useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card"
import { useBalance } from "@/context/BalanceContext"
import { Bomb, Diamond } from "lucide-react"
import { cn } from "@/lib/utils"

const GRID_SIZE = 25

export default function Mines() {
  const { balance, updateBalance } = useBalance()
  const [betAmount, setBetAmount] = useState<number>(10)
  const [mineCount, setMineCount] = useState<number>(3)
  const [isPlaying, setIsPlaying] = useState(false)
  const [mines, setMines] = useState<boolean[]>(Array(GRID_SIZE).fill(false))
  const [revealed, setRevealed] = useState<boolean[]>(Array(GRID_SIZE).fill(false))
  const [gameOver, setGameOver] = useState(false)
  const [message, setMessage] = useState("")
  const [currentMultiplier, setCurrentMultiplier] = useState(1.0)
  const [shake, setShake] = useState(false)

  const startGame = () => {
    if (betAmount > balance) {
      setMessage("Insufficient balance")
      return
    }
    if (isNaN(betAmount) || betAmount <= 0) {
      setMessage("Invalid bet amount")
      return
    }

    setIsPlaying(true)
    setGameOver(false)
    setRevealed(Array(GRID_SIZE).fill(false))
    setMessage("")
    setCurrentMultiplier(1.0)
    updateBalance(-betAmount)
    setShake(false)

    // Place mines randomly
    const newMines = Array(GRID_SIZE).fill(false)
    let placed = 0
    while (placed < mineCount) {
      const idx = Math.floor(Math.random() * GRID_SIZE)
      if (!newMines[idx]) {
        newMines[idx] = true
        placed++
      }
    }
    setMines(newMines)
  }

  const handleTileClick = (index: number) => {
    if (!isPlaying || gameOver || revealed[index]) return

    const newRevealed = [...revealed]
    newRevealed[index] = true
    setRevealed(newRevealed)

    if (mines[index]) {
      // Hit a mine
      setGameOver(true)
      setIsPlaying(false)
      setMessage("BOOM! You hit a mine.")
      setShake(true)
      setTimeout(() => setShake(false), 500)
      // Reveal all mines
      setRevealed(Array(GRID_SIZE).fill(true))
    } else {
      // Safe tile
      // User Formula: multiplier = (25 / safe_tiles_remaining) * 0.97
      // safe_tiles_remaining = (25 - mineCount) - (tiles_revealed_so_far)
      // tiles_revealed_so_far includes the one we just clicked, so we check revealed count
      const safeTilesTotal = GRID_SIZE - mineCount
      const safeTilesFound = newRevealed.filter((r, i) => r && !mines[i]).length
      const safeTilesRemaining = safeTilesTotal - safeTilesFound
      
      // If no safe tiles left (all found), we auto-cashout or handle win, but for now just calc multiplier
      // Note: If safeTilesRemaining is 0, we shouldn't be here (game should end)
      
      // Let's interpret 'safe_tiles_remaining' as the tiles that were remaining *before* this click? 
      // Or simply the formula for the *current state*.
      // If we just clicked, we have found one more.
      
      // Actually, standard probability adds up.
      // Let's use the formula exactly as written for the Total Multiplier of the state.
      // However, if we start with 22 safe, and click 1, we have 21 safe left.
      // (25 / 21) * 0.97 = 1.15x.
      // If we have 1 safe left (near end). (25/1) * 0.97 = 24.25x.
      
      // Adjust: The formula likely means (25 / remaining_safe_at_start_of_pick) ?
      // Let's assume it calculates the accumulated multiplier.
      // Let's try: Next Multiplier = Current Multiplier * (Remaining_Unrevealed / Remaining_Safe) * 0.97?
      // No, user said "multiplier = ...". This implies absolute value.
      
      // Let's stick to the User's text literal:
      // Multiplier = (25 / (25 - mineCount - safeTilesFound)) * 0.97 is likely wrong because it doesn't scale enough.
      
      // ALTERNATIVE INTERPRETATION:
      // it might be ( 25 / safe_tiles_remaining_on_board ).
      // Let's use a standard progressive probability for now but tuned to their "0.97" edge.
      // New Multiplier = Previous * (unrevealed / (unrevealed - mines)) * 0.97
      
      // But I will strictly follow the request: "multiplier = (25 / safe_tiles_remaining) * 0.97"
      // safe_tiles_remaining = (25 - mineCount) - safeTilesFound
      
      const nextMultiplier = (25 / (safeTilesTotal - safeTilesFound)) * 0.97
      // Note: This formula actually drops if safeTilesFound increases? 
      // 25 / 22 = 1.13.    25 / 21 = 1.19.    25 / 1 = 25.
      // Yes, it increases as safe tiles remaining decreases.
      
      setCurrentMultiplier(nextMultiplier)
    }
  }

  const cashOut = () => {
    if (!isPlaying || gameOver) return
    const winnings = betAmount * currentMultiplier
    updateBalance(winnings)
    setIsPlaying(false)
    setGameOver(true)
    setMessage(`Cashed out! You won ${winnings.toFixed(2)} coins!`)
    setRevealed(Array(GRID_SIZE).fill(true)) // Reveal all
  }

  return (
    <div className="flex flex-col items-center justify-center p-4">
      <motion.div
        animate={shake ? { x: [-10, 10, -10, 10, 0] } : {}}
        transition={{ duration: 0.4 }}
        className="w-full max-w-lg"
      >
        <Card className="w-full glass-card border-white/10 bg-black/40">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-2xl text-red-500">
              <Bomb className="h-6 w-6" /> Mines
            </CardTitle>
            <CardDescription className="text-gray-400">Avoid the mines, increase the multiplier, and cash out!</CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="grid grid-cols-5 gap-2 w-full max-w-sm mx-auto p-4 bg-black/30 rounded-xl border border-white/5">
              {Array.from({ length: GRID_SIZE }).map((_, i) => (
                <motion.button
                  key={i}
                  whileHover={!revealed[i] && isPlaying ? { scale: 1.05 } : {}}
                  whileTap={!revealed[i] && isPlaying ? { scale: 0.95 } : {}}
                  onClick={() => handleTileClick(i)}
                  disabled={!isPlaying || gameOver || revealed[i]}
                  className={cn(
                    "aspect-square rounded-lg flex items-center justify-center text-xl transition-all shadow-lg",
                    revealed[i] 
                      ? (mines[i] 
                          ? "bg-red-500/20 border border-red-500 text-red-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]" 
                          : "bg-green-500/20 border border-green-500/50 text-green-400 shadow-[0_0_10px_rgba(34,197,94,0.2)]")
                      : "bg-secondary/50 hover:bg-secondary border border-white/5 hover:border-white/20"
                  )}
                >
                  <AnimatePresence>
                    {revealed[i] && (
                      <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        transition={{ type: "spring", stiffness: 260, damping: 20 }}
                      >
                        {mines[i] ? <Bomb className="h-6 w-6" /> : <Diamond className="h-6 w-6" />}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.button>
              ))}
            </div>

            {!isPlaying && !gameOver && (
              <div className="space-y-4 bg-black/30 p-4 rounded-lg border border-white/5">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-400">Bet Amount</label>
                  <div className="relative">
                    <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">$</span>
                    <Input
                      type="number"
                      value={betAmount}
                      onChange={(e) => setBetAmount(Number(e.target.value))}
                      min={1}
                      className="pl-8 bg-black/50 border-white/10 focus:border-red-500/50 text-white"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-400">Mines (1-24)</label>
                  <Input
                    type="number"
                    value={mineCount}
                    onChange={(e) => setMineCount(Math.min(24, Math.max(1, Number(e.target.value))))}
                    min={1}
                    max={24}
                    className="bg-black/50 border-white/10 focus:border-red-500/50 text-white"
                  />
                </div>
              </div>
            )}

            {isPlaying && (
              <div className="grid grid-cols-2 gap-4 text-center">
                 <div className="bg-black/40 p-3 rounded-lg border border-white/10">
                    <div className="text-xs text-gray-400 uppercase font-bold">Multiplier</div>
                    <div className="text-2xl font-bold text-white">{currentMultiplier.toFixed(2)}x</div>
                 </div>
                 <div className="bg-black/40 p-3 rounded-lg border border-white/10">
                    <div className="text-xs text-gray-400 uppercase font-bold">Potential Win</div>
                    <div className="text-2xl font-bold text-green-400">${(betAmount * currentMultiplier).toFixed(2)}</div>
                 </div>
              </div>
            )}

            <AnimatePresence>
              {message && (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`text-center font-bold text-lg p-2 rounded-lg ${message.includes("won") || message.includes("Cashed") ? "text-green-400 bg-green-400/10 border border-green-400/20" : "text-red-400 bg-red-400/10 border border-red-400/20"}`}
                >
                  {message}
                </motion.div>
              )}
            </AnimatePresence>
          </CardContent>
          <CardFooter className="flex gap-4">
            {!isPlaying ? (
              <Button 
                className="w-full h-12 text-lg font-bold bg-red-600 hover:bg-red-700 text-white shadow-[0_0_20px_rgba(220,38,38,0.4)] border-none"
                onClick={startGame}
              >
                Start Game
              </Button>
            ) : (
              <Button 
                className="w-full h-12 text-lg font-bold bg-green-600 hover:bg-green-700 text-white shadow-[0_0_20px_rgba(22,163,74,0.4)] border-none"
                onClick={cashOut}
              >
                Cash Out ${(betAmount * currentMultiplier).toFixed(2)}
              </Button>
            )}
          </CardFooter>
        </Card>
      </motion.div>
    </div>
  )
}

"use client"

import { useEffect, useRef, useState } from "react"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Label } from "@/components/ui/label"
import { Input } from "@/components/ui/input"
import { useToast } from "@/hooks/use-toast"
import { getMultipliers, PlinkoRisk, PLINKO_ROWS_MIN, PLINKO_ROWS_MAX } from "@/lib/plinko"
import { Loader2, Play } from "lucide-react"
import { motion, AnimatePresence } from "framer-motion"
import Matter from "matter-js"
import { useBalance } from "@/context/BalanceContext"

interface BallData {
  payout: number
  targetPath: number[]
  currentStep: number
  processed: boolean
  targetIndex: number
}

interface BallBody extends Matter.Body {
  plugin: {
    data: BallData
  }
}

export default function PlinkoGame() {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const engineRef = useRef<Matter.Engine | null>(null)
  const runnerRef = useRef<Matter.Runner | null>(null)
  
  const { balance, updateBalance } = useBalance() // Use balance context
  const [wager, setWager] = useState("10")
  const [rows, setRows] = useState(16)
  const [risk, setRisk] = useState<PlinkoRisk>("MEDIUM")
  const [isPlaying, setIsPlaying] = useState(false)
  const { toast } = useToast()
  
  const multipliers = getMultipliers(rows, risk)
  
  // Audio refs
  const dropSound = useRef<HTMLAudioElement | null>(null)
  const winSound = useRef<HTMLAudioElement | null>(null)
  const landSound = useRef<HTMLAudioElement | null>(null)

  useEffect(() => {
    dropSound.current = new Audio('/sounds/drop.mp3')
    winSound.current = new Audio('/sounds/win.mp3')
    landSound.current = new Audio('/sounds/land.mp3') // Add land sound if available
  }, [])

  // Initialize Matter.js Engine
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return

    const engine = Matter.Engine.create()
    const runner = Matter.Runner.create()
    
    // Disable gravity initially (or customize it)
    engine.gravity.y = 1.6 // Stronger gravity for satisfying drop
    engine.gravity.x = 0

    const render = Matter.Render.create({
        canvas: canvas,
        engine: engine,
        options: {
            width: 800,
            height: 600,
            wireframes: false,
            background: 'transparent',
            pixelRatio: window.devicePixelRatio
        }
    })

    Matter.Render.run(render)
    Matter.Runner.run(runner, engine)

    engineRef.current = engine
    runnerRef.current = runner

    return () => {
        Matter.Render.stop(render)
        Matter.Runner.stop(runner)
        if (engineRef.current) Matter.Engine.clear(engineRef.current)
        render.canvas.remove()
        // @ts-expect-error - cleanup
        render.canvas = null
        // @ts-expect-error - cleanup
        render.context = null
        render.textures = {}
    }
  }, [])

  // Re-draw board when rows change
  useEffect(() => {
      if (!engineRef.current) return
      drawBoard()
  }, [rows, risk]) // Re-draw on risk change to update colors

  const drawBoard = () => {
      const engine = engineRef.current
      if (!engine) return

      const world = engine.world
      Matter.World.clear(world, false) // Keep balls (false = keep static? no, false = keep nothing? wait. false = clear everything)
      
      const width = 800
      const height = 600
      const gap = width / (rows + 2)
      const pegRadius = 4

      const pegs = []
      
      for (let r = 0; r < rows; r++) {
          const pegsInRow = r + 3
          // const y = 50 + r * gap // Old spacing
          const y = 80 + r * gap // Move down a bit
          const rowWidth = (pegsInRow - 1) * gap
          const startX = (width - rowWidth) / 2

          for (let c = 0; c < pegsInRow; c++) {
              const x = startX + c * gap
              // Using circle bodies for pegs
              const peg = Matter.Bodies.circle(x, y, pegRadius, {
                  isStatic: true,
                  label: 'peg',
                  render: { fillStyle: 'rgba(255, 255, 255, 0.2)' },
                  restitution: 0.5 // Bounciness
              })
              pegs.push(peg)
          }
      }

      // Buckets / Multipliers
      // We use static bodies (sensors) to detect landing
      const buckets = []
      const y = 80 + rows * gap
      const bucketCount = multipliers.length
      const startX = (width - ((bucketCount) * gap)) / 2 + (gap/2)

      for (let i = 0; i < bucketCount; i++) {
          const x = startX + i * gap
          // Invisible sensor for collision detection
          const sensor = Matter.Bodies.rectangle(x, y + 20, gap - 4, 10, {
              isStatic: true,
              isSensor: true, // Key: Trigger collision events without physical blocking
              label: `bucket-${i}`,
              render: { visible: false } 
          })

          // Visual bucket (we can draw this with Matter.js or separate, let's use Matter bodies for simplicity)
          // Actually, Matter bodies are good but we want text. 
          // We can use the 'afterRender' hook or just trust the standard loop if we wrote one.
          // Since we are using Matter.Render, we can't easily draw text unless we hook into it.
          // BUT, we can add a visual body for the bucket color.
          const bucketVisual = Matter.Bodies.rectangle(x, y + 20, gap - 4, 30, {
            isStatic: true,
            isSensor: true,
            render: { fillStyle: getMultiplierColor(multipliers[i], risk) }
          })

          buckets.push(sensor, bucketVisual)
      }

      // Add Walls slightly off screen to keep balls in bounds just in case
      const ground = Matter.Bodies.rectangle(width/2, height + 50, width, 100, { isStatic: true, label: 'ground' })
      const wallLeft = Matter.Bodies.rectangle(-20, height/2, 40, height, { isStatic: true })
      const wallRight = Matter.Bodies.rectangle(width + 20, height/2, 40, height, { isStatic: true })

      Matter.World.add(world, [...pegs, ...buckets, ground, wallLeft, wallRight])
      
      // Hook into collision events to detect win
      Matter.Events.on(engine, 'collisionStart', (event) => {
          event.pairs.forEach((pair) => {
              const { bodyA, bodyB } = pair
              const ball = bodyA.label.startsWith('ball') ? bodyA : bodyB.label.startsWith('ball') ? bodyB : null
              const bucket = bodyA.label.startsWith('bucket') ? bodyA : bodyB.label.startsWith('bucket') ? bodyB : null
              const ground = bodyA.label === 'ground' ? bodyA : bodyB.label === 'ground' ? bodyB : null

              if (ball && bucket) {
                  // Ball hit a bucket sensor!
                  const bucketIndex = parseInt(bucket.label.split('-')[1])
                  handleWin(ball, bucketIndex)
              }
              
              if (ball && ground) {
                  // Fallback: Remove ball if it hits ground without hitting bucket
                  Matter.World.remove(world, ball)
              }
          })
      })
  }

  const handleWin = (ballBody: Matter.Body, bucketIndex: number) => {
      // Validate with the data attached to the ball
      const ballWithData = ballBody as BallBody
      const ballData = ballWithData.plugin.data
      if (ballData.processed) return
      
      ballData.processed = true // Prevent double triggering
      
      // Delay removal slightly for visual effect? No, simple is better.
      Matter.World.remove(engineRef.current!.world, ballBody)
      
      // Trigger Balance Update HERE (Visual Freeze Effect)
      // We only add the payout. The wager was deducted at start.
      if (ballData.payout > 0) {
          updateBalance(ballData.payout, true)
          // Play win sound
          if (winSound.current) {
              winSound.current.currentTime = 0
              winSound.current.play().catch(() => {})
          }
          toast({
                title: `${multipliers[bucketIndex]}x Multiplier!`,
                description: `You won ${ballData.payout.toFixed(2)}`,
                className: "bg-green-600 text-white border-none"
            })
      } else {
        // Loss
        // No balance update needed (already deducted)
      }
  }

  const getMultiplierColor = (val: number, risk: PlinkoRisk) => {
       if (val < 1) return '#3f3f46' // zinc-700
       if (val < 3) return '#fbbf24' // amber-400
       if (val < 10) return '#f97316' // orange-500
       return '#ef4444' // red-500
  }

  const dropBall = async () => {
    const amount = parseFloat(wager)
    if (!amount || isNaN(amount) || amount <= 0) {
        toast({ title: "Invalid Wager", variant: "destructive" })
        return
    }
    if (balance < amount) {
        toast({ title: "Insufficient Balance", variant: "destructive" })
        return
    }

    try {
        // 1. Optimistic Deduction (Freeze funds)
        await updateBalance(-amount, true)

        const res = await fetch('/api/games/plinko/play', {
            method: 'POST',
            body: JSON.stringify({
                wager: amount,
                risk,
                rows
            })
        })
        const data = await res.json()
        
        if (!data.success) {
            // Refund on error
            await updateBalance(amount, true)
            throw new Error(data.error)
        }

        // 2. Add Ball to Physics World
        const engine = engineRef.current
        if (!engine) return

        // Calculate random start position based on path? 
        // Real Plinko logic requires the ball to bounce specifically to land in the target.
        // Since physics is chaotic, we can't easily force it to land in index X using just physics 
        // unless we have a "rigged" physics engine or invisible guides.
        //
        // SOLUTION: "Guided" Physics or pure visual simulation?
        // User asked for "realistic ball movement" (Physics).
        // If we use real physics, the result is random. But the SERVER determined the result already.
        // Hybrid Approach: We spawn the ball and apply tiny forces to nudge it towards the target path? 
        // OR: We just let it drop and if it lands in the wrong bucket, we lie about the visual? No, that's bad.
        //
        // Standard Crypto Casino Approach:
        // The "physics" is often pre-calculated or faked visually to matching the path.
        // OR: We can simulate the path by adding invisible walls/forces.
        // 
        // For this task, to satisfy "Matter.js" and "Realistic":
        // We will drop the ball. We will NOT nudge it.
        // Wait, if we don't nudge it, it won't match the server result `data.result.index`.
        // This creates a discrepancy between "Proven Fair" result and "Visual" result.
        //
        // CRITICAL FIX: We must visual-only simulate the path provided by server `data.result.path`?
        // Actually, matching exact physics to a pre-determined path is VERY hard.
        // For this demo, and since user prioritized "Visuals/Physics", I will:
        // Spawn the ball with a specific offset/variable X velocity that statistically favors the target?
        // No, that's unreliable.
        // 
        // Alternative: The path is `[0, 1, 0, 1...]` (Left/Right).
        // We can nudge the ball left/right at each peg collision to match the path.
        // Events.on(engine, 'collisionStart') -> check if peg -> apply force based on current step in path.
        
        const ball = Matter.Bodies.circle(400 + (Math.random() - 0.5) * 10, 20, 6, {
            restitution: 0.5,
            friction: 0.5,
            label: 'ball',
            render: { fillStyle: '#ffff00' },
            plugin: {
                data: {
                    payout: data.result.payout,
                    targetPath: data.result.path, // [0, 1, 0, 1 (right)]
                    currentStep: 0,
                    processed: false,
                    targetIndex: data.result.index
                }
            }
        })
        
        // Add random jitter to ensure it doesn't get stuck
        Matter.Body.setVelocity(ball, { x: (Math.random() - 0.5), y: 0 })

        Matter.World.add(engine.world, ball)
        
        // Play drop sound
        if (dropSound.current) {
            dropSound.current.currentTime = 0
            dropSound.current.play().catch(() => {})
        }

    } catch (e) {
        const msg = e instanceof Error ? e.message : "An error occurred"
        toast({ title: "Error", description: msg, variant: "destructive" })
    }
  }
  
  // Custom Collision Logic to Guide Ball (Hybrid Physics)
  useEffect(() => {
      const engine = engineRef.current
      if (!engine) return
      
      const onCollision = (event: Matter.IEventCollision<Matter.Engine>) => {
          event.pairs.forEach((pair) => {
              const { bodyA, bodyB } = pair
              const ball = bodyA.label === 'ball' ? bodyA : bodyB.label === 'ball' ? bodyB : null
              const peg = bodyA.label === 'peg' ? bodyA : bodyB.label === 'peg' ? bodyB : null
              
              if (ball && peg) {
                  const ballWithData = ball as BallBody
                  const ballData = ballWithData.plugin.data
                  const path = ballData.targetPath
                  const step = ballData.currentStep
                  
                  if (step < path.length) {
                      // 0 = Left, 1 = Right
                      const direction = path[step] === 1 ? 1 : -1
                      
                      // Nudge the ball in the target direction
                      // Applying a small force to override chaotic bounce
                      const forceMagnitude = 0.002 // Tweak this value
                      Matter.Body.applyForce(ball, ball.position, { x: direction * forceMagnitude, y: 0 })
                      
                      ballData.currentStep++
                  }
              }
          })
      }
      
      Matter.Events.on(engine, 'collisionStart', onCollision)
      
      return () => {
          Matter.Events.off(engine, 'collisionStart', onCollision)
      }
  }, []) // Bind once

  return (
    <div className="flex flex-col lg:flex-row gap-8 max-w-6xl mx-auto p-4">
      {/* Controls Sidebar */}
      <Card className="w-full lg:w-80 p-6 space-y-6 h-fit bg-black/40 border-white/10 backdrop-blur-md">
        <div className="space-y-2">
            <Label>Wager Amount</Label>
            <div className="relative">
                <Input 
                    type="number" 
                    value={wager} 
                    onChange={e => setWager(e.target.value)}
                    className="bg-black/20 border-white/10"
                />
                <div className="absolute right-1 top-1 flex gap-1">
                    <Button size="xs" variant="ghost" onClick={() => setWager((parseFloat(wager)/2).toString())}>┬╜</Button>
                    <Button size="xs" variant="ghost" onClick={() => setWager((parseFloat(wager)*2).toString())}>2├ù</Button>
                </div>
            </div>
        </div>

        <div className="space-y-2">
            <Label>Risk Level</Label>
            <Select value={risk} onValueChange={(v: PlinkoRisk) => setRisk(v)}>
                <SelectTrigger className="bg-black/20 border-white/10">
                    <SelectValue />
                </SelectTrigger>
                <SelectContent>
                    <SelectItem value="LOW">Low</SelectItem>
                    <SelectItem value="MEDIUM">Medium</SelectItem>
                    <SelectItem value="HIGH">High</SelectItem>
                </SelectContent>
            </Select>
        </div>

        <div className="space-y-2">
            <Label>Rows: {rows}</Label>
            <Select value={rows.toString()} onValueChange={(v: string) => setRows(parseInt(v))}>
                <SelectTrigger className="bg-black/20 border-white/10">
                    <SelectValue />
                </SelectTrigger>
                <SelectContent>
                    {Array.from({length: 9}, (_, i) => i + 8).map(r => (
                        <SelectItem key={r} value={r.toString()}>{r}</SelectItem>
                    ))}
                </SelectContent>
            </Select>
        </div>

        <Button 
            className="w-full h-12 text-lg font-bold bg-green-500 hover:bg-green-600 text-black"
            onClick={dropBall}
        >
            Bet
        </Button>
      </Card>

      {/* Game Canvas */}
      <div className="flex-1 flex justify-center bg-black/20 rounded-3xl p-8 border border-white/5 relative min-h-[600px] items-center">
         <canvas 
            ref={canvasRef}
            className="max-w-full h-auto rounded-xl"
         />
         {!isPlaying && false && ( // Disabled simplistic overlay
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                 <span className="text-white/20 text-4xl font-black uppercase tracking-widest">Plinko</span>
             </div>
         )}
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { User, Mail, Camera, Save, Loader } from 'lucide-react'
import Image from 'next/image'

interface ProfileData {
  id: string
  name: string
  email: string
  avatar?: string
  bio?: string
}

export default function ProfileSettings() {
  const [name, setName] = useState('')
  const [email, setEmail] = useState('')
  const [bio, setBio] = useState('')
  const [avatar, setAvatar] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [avatarFile, setAvatarFile] = useState<File | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    fetchProfile()
  }, [])

  const fetchProfile = async () => {
    try {
      const res = await fetch('/api/user/profile')
      const data = await res.json()
      
      if (data.success) {
        setName(data.user.name || '')
        setEmail(data.user.email || '')
        setBio(data.user.bio || '')
        setAvatar(data.user.avatar || null)
      }
    } catch (error) {
      console.error('Failed to fetch profile:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        alert('File size must be less than 5MB')
        return
      }
      
      if (!file.type.startsWith('image/')) {
        alert('Please select an image file')
        return
      }

      setAvatarFile(file)
      const reader = new FileReader()
      reader.onloadend = () => {
        setAvatar(reader.result as string)
      }
      reader.readAsDataURL(file)
    }
  }

  const handleSave = async () => {
    setSaving(true)
    try {
      // Upload avatar first if changed
      let avatarUrl = avatar
      if (avatarFile) {
        const formData = new FormData()
        formData.append('avatar', avatarFile)

        const avatarRes = await fetch('/api/user/settings/avatar', {
          method: 'POST',
          body: formData,
        })

        const avatarData = await avatarRes.json()
        if (avatarData.success) {
          avatarUrl = avatarData.avatarUrl
        }
      }

      // Update profile
      const res = await fetch('/api/user/settings/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name,
          email,
          bio,
          avatar: avatarUrl,
        }),
      })

      const data = await res.json()

      if (data.success) {
        alert('Profile updated successfully!')
        fetchProfile()
      } else {
        alert(data.error || 'Failed to update profile')
      }
    } catch (error) {
      console.error('Update error:', error)
      alert('Failed to update profile')
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader className="w-8 h-8 animate-spin text-primary" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl md:text-3xl font-bold text-white mb-2">Profile Settings</h2>
        <p className="text-gray-400">Manage your personal information</p>
      </div>

      {/* Avatar Upload */}
      <div className="flex flex-col items-center gap-4 p-6 rounded-xl bg-black/20">
        <div className="relative">
          <div className="w-32 h-32 rounded-full overflow-hidden bg-gradient-primary flex items-center justify-center text-5xl font-bold">
            {avatar ? (
              <Image src={avatar} alt="Avatar" width={128} height={128} className="w-full h-full object-cover" />
            ) : (
              <span>{name?.charAt(0).toUpperCase() || 'U'}</span>
            )}
          </div>
          <button
            onClick={() => fileInputRef.current?.click()}
            className="absolute bottom-0 right-0 p-2 rounded-full bg-primary hover:bg-primary/80 transition-colors"
          >
            <Camera className="w-5 h-5 text-white" />
          </button>
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            onChange={handleAvatarChange}
            className="hidden"
          />
        </div>
        <p className="text-sm text-gray-400">Click camera icon to upload new avatar (max 5MB)</p>
      </div>

      {/* Form Fields */}
      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-300 mb-2">
            <User className="w-4 h-4 inline mr-2" />
            Full Name
          </label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Enter your name"
            className="w-full px-4 py-3 rounded-xl bg-black/40 border border-white/10 text-white focus:border-primary focus:outline-none"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-2">
            <Mail className="w-4 h-4 inline mr-2" />
            Email Address
          </label>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Enter your email"
            className="w-full px-4 py-3 rounded-xl bg-black/40 border border-white/10 text-white focus:border-primary focus:outline-none"
          />
          <p className="text-xs text-gray-500 mt-1">
            Changing email will require verification
          </p>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-2">
            Bio
          </label>
          <textarea
            value={bio}
            onChange={(e) => setBio(e.target.value)}
            placeholder="Tell us about yourself..."
            rows={4}
            maxLength={500}
            className="w-full px-4 py-3 rounded-xl bg-black/40 border border-white/10 text-white focus:border-primary focus:outline-none resize-none"
          />
          <p className="text-xs text-gray-500 mt-1">
            {bio.length}/500 characters
          </p>
        </div>
      </div>

      {/* Save Button */}
      <button
        onClick={handleSave}
        disabled={saving}
        className="w-full btn-primary py-3 flex items-center justify-center gap-2 disabled:opacity-50"
      >
        {saving ? (
          <>
            <Loader className="w-5 h-5 animate-spin" />
            Saving...
          </>
        ) : (
          <>
            <Save className="w-5 h-5" />
            Save Changes
          </>
        )}
      </button>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Smartphone, Key, Lock, AlertTriangle, Check, Copy, Loader, Monitor, X } from 'lucide-react'
import Image from 'next/image'

interface Session {
  id: string
  deviceInfo: string
  ipAddress: string
  lastActive: string
  current: boolean
}

function TransactionPasswordSection() {
  const [isSet, setIsSet] = useState(false)
  const [loading, setLoading] = useState(false)
  const [showForm, setShowForm] = useState(false)
  const [currentPassword, setCurrentPassword] = useState('')
  const [newTxPassword, setNewTxPassword] = useState('')

  useEffect(() => {
    fetchStatus()
  }, [])

  const fetchStatus = async () => {
    try {
      const res = await fetch('/api/user/settings/transaction-password')
      const data = await res.json()
      if (data.success) setIsSet(data.isSet)
    } catch (e) { console.error(e) }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    try {
      const res = await fetch('/api/user/settings/transaction-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ currentPassword, newTransactionPassword: newTxPassword }),
      })
      const data = await res.json()
      if (data.success) {
        alert('Transaction password set successfully!')
        setShowForm(false)
        setCurrentPassword('')
        setNewTxPassword('')
        fetchStatus()
      } else {
        alert(data.error || 'Failed to set transaction password')
      }
    } catch (e) {
      alert('Failed to set transaction password')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="p-6 rounded-xl bg-black/20 border border-white/10">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h3 className="text-xl font-bold text-white flex items-center gap-2">
            <Key className="w-5 h-5" />
            Transaction Password
          </h3>
          <p className="text-sm text-gray-400 mt-1">
            {isSet ? 'Secondary password required for withdrawals and sensitive actions.' : 'Set a secondary password for extra security.'}
          </p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="btn-secondary px-4 py-2"
        >
          {showForm ? 'Cancel' : isSet ? 'Change' : 'Set Now'}
        </button>
      </div>

      {showForm && (
        <motion.form
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          onSubmit={handleSubmit}
          className="space-y-4 mt-4"
        >
          <div>
            <label className="block text-sm text-gray-300 mb-2">Account Password (to verify it&apos;s you)</label>
            <input
              type="password"
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
              className="w-full px-4 py-3 rounded-xl bg-black/40 border border-white/10 text-white focus:border-primary focus:outline-none"
              required
            />
          </div>
          <div>
            <label className="block text-sm text-gray-300 mb-2">New Transaction Password (6+ characters)</label>
            <input
              type="password"
              value={newTxPassword}
              onChange={(e) => setNewTxPassword(e.target.value)}
              className="w-full px-4 py-3 rounded-xl bg-black/40 border border-white/10 text-white focus:border-primary focus:outline-none"
              required
              minLength={6}
            />
          </div>
          <button
            type="submit"
            disabled={loading}
            className="btn-primary px-6 py-3 disabled:opacity-50"
          >
            {loading ? 'Saving...' : 'Save Transaction Password'}
          </button>
        </motion.form>
      )}
    </div>
  )
}

export default function SecuritySettings() {
  const [twoFactorEnabled, setTwoFactorEnabled] = useState(false)
  const [showSetup, setShowSetup] = useState(false)
  const [qrCode, setQrCode] = useState('')
  const [secret, setSecret] = useState('')
  const [verificationCode, setVerificationCode] = useState('')
  const [backupCodes, setBackupCodes] = useState<string[]>([])
  const [loading, setLoading] = useState(false)
  const [copied, setCopied] = useState(false)
  
  // Password change
  const [showPasswordForm, setShowPasswordForm] = useState(false)
  const [currentPassword, setCurrentPassword] = useState('')
  const [newPassword, setNewPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  
  // Sessions
  const [sessions, setSessions] = useState<Session[]>([])
  const [loadingSessions, setLoadingSessions] = useState(true)

  useEffect(() => {
    fetchSecurityStatus()
    fetchSessions()
  }, [])

  const fetchSecurityStatus = async () => {
    try {
      const res = await fetch('/api/user/security/status')
      const data = await res.json()
      if (data.success) {
        setTwoFactorEnabled(data.twoFactorEnabled || false)
      }
    } catch (error) {
      console.error('Failed to fetch security status:', error)
    }
  }

  const fetchSessions = async () => {
    try {
      const res = await fetch('/api/user/settings/sessions')
      const data = await res.json()
      if (data.success) {
        setSessions(data.sessions || [])
      }
    } catch (error) {
      console.error('Failed to fetch sessions:', error)
    } finally {
      setLoadingSessions(false)
    }
  }

  const startSetup = async () => {
    setLoading(true)
    try {
      const res = await fetch('/api/auth/2fa/setup', { method: 'POST' })
      const data = await res.json()
      
      if (data.success) {
        setQrCode(data.qrCode)
        setSecret(data.secret)
        setShowSetup(true)
      } else {
        alert(data.error || 'Failed to start 2FA setup')
      }
    } catch (error) {
      console.error('2FA setup error:', error)
      alert('Failed to start 2FA setup')
    } finally {
      setLoading(false)
    }
  }

  const verifyAndEnable = async () => {
    if (verificationCode.length !== 6) {
      alert('Please enter a 6-digit code')
      return
    }

    setLoading(true)
    try {
      const res = await fetch('/api/auth/2fa/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: verificationCode, secret }),
      })

      const data = await res.json()
      
      if (data.success) {
        setBackupCodes(data.backupCodes)
        setTwoFactorEnabled(true)
        setVerificationCode('')
      } else {
        alert(data.error || 'Invalid verification code')
      }
    } catch (error) {
      console.error('2FA verification error:', error)
      alert('Failed to verify code')
    } finally {
      setLoading(false)
    }
  }

  const disable2FA = async () => {
    const password = prompt('Enter your password to disable 2FA:')
    if (!password) return

    setLoading(true)
    try {
      const res = await fetch('/api/auth/2fa/disable', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password }),
      })

      const data = await res.json()
      
      if (data.success) {
        setTwoFactorEnabled(false)
        setShowSetup(false)
        setBackupCodes([])
        alert('2FA disabled successfully')
      } else {
        alert(data.error || 'Failed to disable 2FA')
      }
    } catch (error) {
      console.error('2FA disable error:', error)
      alert('Failed to disable 2FA')
    } finally {
      setLoading(false)
    }
  }

  const copyBackupCodes = () => {
    navigator.clipboard.writeText(backupCodes.join('\n'))
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault()

    if (newPassword.length < 8) {
      alert('Password must be at least 8 characters')
      return
    }

    if (newPassword !== confirmPassword) {
      alert('Passwords do not match')
      return
    }

    setLoading(true)
    try {
      const res = await fetch('/api/user/settings/password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ currentPassword, newPassword }),
      })

      const data = await res.json()

      if (data.success) {
        alert('Password changed successfully!')
        setShowPasswordForm(false)
        setCurrentPassword('')
        setNewPassword('')
        setConfirmPassword('')
      } else {
        alert(data.error || 'Failed to change password')
      }
    } catch (error) {
      console.error('Password change error:', error)
      alert('Failed to change password')
    } finally {
      setLoading(false)
    }
  }

  const logoutSession = async (sessionId: string) => {
    if (!confirm('Are you sure you want to logout this session?')) return

    try {
      const res = await fetch(`/api/user/settings/sessions?sessionId=${sessionId}`, {
        method: 'DELETE',
      })

      const data = await res.json()

      if (data.success) {
        setSessions(sessions.filter(s => s.id !== sessionId))
        alert('Session logged out successfully')
      } else {
        alert(data.error || 'Failed to logout session')
      }
    } catch (error) {
      console.error('Logout session error:', error)
      alert('Failed to logout session')
    }
  }

  const logoutAllSessions = async () => {
    if (!confirm('Are you sure you want to logout all other sessions? You will remain logged in on this device.')) return

    try {
      const res = await fetch('/api/user/settings/sessions?all=true', {
        method: 'DELETE',
      })

      const data = await res.json()

      if (data.success) {
        fetchSessions()
        alert('All other sessions logged out successfully')
      } else {
        alert(data.error || 'Failed to logout sessions')
      }
    } catch (error) {
      console.error('Logout all error:', error)
      alert('Failed to logout sessions')
    }
  }

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl md:text-3xl font-bold text-white mb-2">Security Settings</h2>
        <p className="text-gray-400">Manage your account security and authentication</p>
      </div>

      {/* Password Section */}
      <div className="p-6 rounded-xl bg-black/20 border border-white/10">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="text-xl font-bold text-white flex items-center gap-2">
              <Lock className="w-5 h-5" />
              Account Password
            </h3>
            <p className="text-sm text-gray-400 mt-1">Change your account password</p>
          </div>
          <button
            onClick={() => setShowPasswordForm(!showPasswordForm)}
            className="btn-secondary px-4 py-2"
          >
            {showPasswordForm ? 'Cancel' : 'Change Password'}
          </button>
        </div>

        {showPasswordForm && (
          <motion.form
            initial={{ opacity: 0, height: 0 }}
