"use client"

import * as React from "react"
import type { ToastActionElement, ToastProps } from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
    type: ActionType["ADD_TOAST"]
    toast: ToasterToast
  }
  | {
    type: ActionType["UPDATE_TOAST"]
    toast: Partial<ToasterToast>
  }
  | {
    type: ActionType["DISMISS_TOAST"]
    toastId?: ToasterToast["id"]
  }
  | {
    type: ActionType["REMOVE_TOAST"]
    toastId?: ToasterToast["id"]
  }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
              ...t,
              open: false,
            }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open: boolean) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

'use client'

import { useEffect, useState, useCallback } from 'react'
import { io, Socket } from 'socket.io-client'
import { useSession } from 'next-auth/react'

import { SharedBet, SharedUser, SharedTransaction } from '@/types'

interface BalanceUpdate {
  userId: string
  balance: number
  type: 'MAIN' | 'BONUS'
}

interface ChatMessage {
  id: string
  userId: string
  userEmail: string
  message: string
  timestamp: Date
}

export function useWebSocket() {
  const [socket, setSocket] = useState<Socket | null>(null)
  const [connected, setConnected] = useState(false)
  const { data: session } = useSession()

  useEffect(() => {
    const socketInstance = io({
      path: '/socket.io',
      addTrailingSlash: false,
      autoConnect: false,
    })

    socketInstance.on('connect', () => {
      console.log('[WebSocket] Connected:', socketInstance.id)
      setConnected(true)

      // Authenticate if session exists
      if (session?.user?.id) {
        socketInstance.emit('authenticate', session.user.id)
      }
    })

    socketInstance.on('disconnect', () => {
      console.log('[WebSocket] Disconnected')
      setConnected(false)
    })

    socketInstance.on('auth:success', (data: { userId: string }) => {
      console.log('[WebSocket] Authenticated:', data.userId)
    })

    socketInstance.on('auth:error', (error: string) => {
      console.error('[WebSocket] Auth error:', error)
    })

    socketInstance.connect()

    // Use microtask to avoid synchronous state update in effect warning
    Promise.resolve().then(() => {
      setSocket(socketInstance)
    })

    return () => {
      socketInstance.disconnect()
      setSocket(null)
    }
  }, [session?.user?.id])

  return { socket, connected }
}

/**
 * Hook for live bets feed
 */
export function useLiveBets() {
  const { socket } = useWebSocket()
  const [bets, setBets] = useState<SharedBet[]>([])

  useEffect(() => {
    if (!socket) return

    const handleNewBet = (bet: SharedBet) => {
      setBets((prev) => [bet, ...prev].slice(0, 50)) // Keep last 50 bets
    }

    socket.on('bet:new', handleNewBet)

    return () => {
      socket.off('bet:new', handleNewBet)
    }
  }, [socket])

  return { bets }
}

/**
 * Hook for wallet balance updates
 */
export function useWalletUpdates(userId?: string) {
  const { socket } = useWebSocket()
  const [balance, setBalance] = useState<BalanceUpdate | null>(null)

  useEffect(() => {
    if (!socket || !userId) return

    const handleBalanceUpdate = (update: BalanceUpdate) => {
      setBalance(update)
    }

    socket.on(`balance:${userId}`, handleBalanceUpdate)

    return () => {
      socket.off(`balance:${userId}`, handleBalanceUpdate)
    }
  }, [socket, userId])

  return { balance }
}

/**
 * Hook for game room
 */
export function useGameRoom(roomId: string) {
  const { socket, connected } = useWebSocket()
  const [joined, setJoined] = useState(false)
  const [messages, setMessages] = useState<ChatMessage[]>([])

  useEffect(() => {
    if (!socket || !connected) return

    // Join room
    socket.emit('room:join', roomId)

    socket.on('room:joined', () => {
      setJoined(true)
    })

    socket.on('chat:message', (message: ChatMessage) => {
      setMessages((prev) => [...prev, message])
    })

    return () => {
      socket.emit('room:leave', roomId)
      setJoined(false)
    }
  }, [socket, connected, roomId])

  const sendMessage = useCallback(
    (message: string) => {
      if (!socket || !joined) return
      socket.emit('chat:send', { roomId, message })
    },
    [socket, joined, roomId]
  )

  return { joined, messages, sendMessage }
}

import prisma from "@/lib/prisma"

export class IdempotencyService {
  /**
   * Check if a key exists and returns its status/response.
   * Throws if key is locked (processing).
   */
  static async check(key: string, _userId: string) {
    const existing = await prisma.idempotencyRequest.findUnique({
      where: { key }
    })

    if (!existing) return null

    // If request exists but no response/status yet, it's pending/locked
    if (existing.statusCode === null) {
      // Check if lock is stale (e.g. > 1 min)
      const now = new Date()
      const lockAge = now.getTime() - existing.lockedAt.getTime()

      if (lockAge > 60000) {
        // Stale lock - assume failed/crashed and allow retry (delete or update)
        // For safety in money matters, we might want to manually review, but for now allow retry
        await prisma.idempotencyRequest.delete({ where: { key } })
        return null
      }

      throw new Error("Request is being processed (Idempotency Lock)")
    }

    return existing
  }

  /**
   * Create a lock for this key.
   */
  static async lock(key: string, userId: string, path: string, params?: unknown) {
    // Attempt to create. If key exists, unique constraint might fail or we handled it in check()
    // Using upsert or strict create. Strict create is better for idempotency.
    try {
      await prisma.idempotencyRequest.create({
        data: {
          key,
          userId,
          path,
          params: params ? JSON.parse(JSON.stringify(params)) : undefined,
          lockedAt: new Date()
        }
      })
    } catch (e) {
      if (e && typeof e === 'object' && 'code' in e && (e as { code: string }).code === 'P2002') {
        throw new Error("Request already exists")
      }
      throw e
    }
  }

  /**
   * Update the record with the response.
   */
  static async complete(key: string, statusCode: number, response: unknown) {
    await prisma.idempotencyRequest.update({
      where: { key },
      data: {
        statusCode,
        response: response ? JSON.parse(JSON.stringify(response)) : undefined
      }
    })
  }
}

import prisma from "@/lib/prisma"
import { IdempotencyRequest, Prisma } from "@prisma/client"

export class IdempotencyService {
  /**
   * Lock a request by key. Throws error if already locked/processing.
   * If completed, returns the stored response.
   */
  static async lock(key: string, userId: string, path: string, params: unknown) {
    // 1. Check if exists
    const existing = await prisma.idempotencyRequest.findUnique({
      where: { key }
    })

    if (existing) {
      // If response exists, it's completed. Return it.
      if (existing.response) {
        return {
          status: 'COMPLETED',
          response: existing.response,
          statusCode: existing.statusCode
        }
      }

      // If no response, check if it's stale (e.g., > 1 minute old) presumably crashed
      const isStale = Date.now() - existing.lockedAt.getTime() > 60 * 1000
      if (!isStale) {
        throw new Error("Request still processing") // 429 or 409
      }

      // If stale, we update/takeover (or just fail? fail safer)
      // For now, let's update lockedAt and retry
      await prisma.idempotencyRequest.update({
        where: { key },
        data: { lockedAt: new Date() }
      })
      return { status: 'PROCESSING' }
    }

    // 2. Create new lock
    await prisma.idempotencyRequest.create({
      data: {
        key,
        userId,
        path,
        params: params || {},
        lockedAt: new Date()
      }
    })

    return { status: 'PROCESSING' }
  }

  /**
   * Complete a request by storing the response.
   */
  static async complete(key: string, response: unknown, statusCode: number) {
    try {
      await prisma.idempotencyRequest.update({
        where: { key },
        data: {
          response: response as Prisma.InputJsonValue,
          statusCode: statusCode
        }
      })
    } catch (e) {
      console.error("Failed to complete idempotency request", e)
      // Request might have been deleted/expired
    }
  }

  /**
   * Generate a deterministic key if client doesn't provide one (e.g. hash of params + userId)
   */
  static generateKey(userId: string, path: string, params: unknown): string {
    const data = JSON.stringify({ userId, path, params })
    // Simple hash (for demo, use crypto in prod)
    let hash = 0, i, chr;
    if (data.length === 0) return hash.toString();
    for (i = 0; i < data.length; i++) {
      chr = data.charCodeAt(i);
      hash = ((hash << 5) - hash) + chr;
      hash |= 0; // Convert to 32bit integer
    }
    return `auto-${hash}`;
  }
}

import prisma from '@/lib/prisma'
import { DepositStatus, WithdrawalStatus, PaymentMethod, TransactionType, TransactionStatus, UserRole } from '@prisma/client'
import { WalletService } from './wallet.service'
import { AuditService } from './audit.service'
import { NotificationService } from './notification.service'
import bcrypt from 'bcryptjs'

/**
 * Payment Service - Handles deposits and withdrawals
 */
export class PaymentService {
  /**
   * Create deposit request
   */
  static async createDeposit(params: {
    userId: string
    amount: number
    method: PaymentMethod
    upiId?: string
  }) {
    const { userId, amount, method, upiId } = params

    if (amount < 100) throw new Error('Minimum deposit is Γé╣100')
    if (amount > 100000) throw new Error('Maximum deposit is Γé╣1,00,000')

    const deposit = await prisma.deposit.create({
      data: {
        userId,
        amount,
        method,
        upiId,
        status: DepositStatus.PENDING,
      },
    })

    await AuditService.logDeposit(userId, deposit.id, amount)
    return deposit
  }

  /**
   * Complete deposit (called by webhook or admin approval)
   */
  static async completeDeposit(depositId: string) {
    const deposit = await prisma.deposit.findUnique({
      where: { id: depositId },
    })

    if (!deposit) throw new Error('Deposit not found')
    if (deposit.status === DepositStatus.COMPLETED) {
      throw new Error('Deposit already completed')
    }

    // 1. Credit wallet via WalletService (handles atomicity and logging)
    await WalletService.deposit(deposit.userId, deposit.amount, depositId)

    // 2. Update deposit status
    const updatedDeposit = await prisma.deposit.update({
      where: { id: depositId },
      data: {
        status: DepositStatus.COMPLETED,
        completedAt: new Date(),
      },
    })

    // 3. Post-transaction actions
    await NotificationService.notifyDeposit(deposit.userId, deposit.amount)

    // 4. Referral rewards
    const user = await prisma.user.findUnique({
      where: { id: deposit.userId },
      select: { referredBy: true },
    })

    if (user?.referredBy) {
      const depositsCount = await prisma.deposit.count({
        where: { userId: deposit.userId, status: DepositStatus.COMPLETED },
      })

      if (depositsCount === 1) {
        const { BonusService } = await import('./bonus.service')
        await BonusService.grantReferralBonus(user.referredBy, deposit.userId, 'FIRST_DEPOSIT')
      }
    }

    return updatedDeposit
  }

  /**
   * Create withdrawal request
   */
  static async createWithdrawal(params: {
    userId: string
    amount: number
    method: PaymentMethod
    otp: string
    bankName?: string
    accountNumber?: string
    ifscCode?: string
    upiId?: string
    cryptoAddress?: string
  }) {
    const { userId, amount, method, otp, ...bankDetails } = params

    if (amount < 500) throw new Error('Minimum withdrawal is Γé╣500')
    if (amount > 50000) throw new Error('Maximum withdrawal per request is Γé╣50,000')

    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { transactionPassword: true, kycStatus: true },
    })

    if (!user) throw new Error('User not found')
    if (user.kycStatus !== 'APPROVED') throw new Error('KYC verification required for withdrawals')

    // Transaction Password Verification
    if (!user.transactionPassword) throw new Error('Please set a transaction password in settings first.')

    // Check if OTP (split by :) or Hashed Password (bcrypt usually starts with $2)
    // To maintain compatibility or just switch fully, let's switch fully.
    const isTxPasswordValid = await bcrypt.compare(otp, user.transactionPassword)
    if (!isTxPasswordValid) throw new Error('Invalid transaction password')

    const fee = Math.max(10, amount * 0.02)
    const finalAmount = amount - fee

    const withdrawal = await prisma.withdrawal.create({
      data: {
        userId,
        amount,
        fee,
        finalAmount,
        method,
        ...bankDetails,
        status: WithdrawalStatus.PENDING,
      },
    })

    try {
      // LOCK FUNDS IMMEDIATELY ΓÇö moves amount from mainBalance ΓåÆ lockedBalance atomically
      await WalletService.lockForWithdrawal(userId, amount, withdrawal.id)

      // NOTE: transactionPassword is a permanent credential, NOT a one-time OTP.
      // It must NOT be cleared here; the user needs it for future withdrawals.

      await AuditService.logWithdrawal(userId, withdrawal.id, amount)
      return withdrawal
    } catch (error) {
      await prisma.withdrawal.delete({ where: { id: withdrawal.id } })
      throw error
    }
  }

  /**
   * Approve withdrawal (admin only)
   */
  static async approveWithdrawal(withdrawalId: string, adminId: string, notes?: string) {
    const withdrawal = await prisma.withdrawal.findUnique({
      where: { id: withdrawalId },
    })

    if (!withdrawal) throw new Error('Withdrawal not found')
    if (withdrawal.status !== WithdrawalStatus.PENDING) {
      throw new Error('Withdrawal already processed')
    }

    // 1. Deduct from locked balance permanently
    await WalletService.completeWithdrawalFromLocked(withdrawal.userId, withdrawal.amount, withdrawalId)

    // 2. Update record
    const updatedWithdrawal = await prisma.withdrawal.update({
      where: { id: withdrawalId },
      data: {
        status: WithdrawalStatus.APPROVED,
        approvedBy: adminId,
        approvedAt: new Date(),
        adminNotes: notes,
      },
    })

    // 3. Notifications & Audit
    await NotificationService.notifyWithdrawal(withdrawal.userId, withdrawal.finalAmount, 'APPROVED')
    await AuditService.logAdminAction(adminId, 'APPROVE_WITHDRAWAL', withdrawal.userId, { withdrawalId, amount: withdrawal.amount })

    return updatedWithdrawal
  }

  /**
   * Reject withdrawal (admin only)
   */
  static async rejectWithdrawal(withdrawalId: string, adminId: string, reason: string) {
    const withdrawal = await prisma.withdrawal.findUnique({
      where: { id: withdrawalId },
    })

    if (!withdrawal) throw new Error('Withdrawal not found')
    if (withdrawal.status !== WithdrawalStatus.PENDING) {
      throw new Error('Withdrawal already processed')
    }

    // 1. Refund funds to main balance
    await WalletService.refundWithdrawal(withdrawal.userId, withdrawal.amount, withdrawalId, reason)

    // 2. Update record
    const updatedWithdrawal = await prisma.withdrawal.update({
      where: { id: withdrawalId },
      data: {
        status: WithdrawalStatus.REJECTED,
        rejectedReason: reason,
        processedAt: new Date(),
      },
    })

    // 3. Notifications & Audit
    await NotificationService.notifyWithdrawal(withdrawal.userId, withdrawal.amount, 'REJECTED')
    await AuditService.logAdminAction(adminId, 'REJECT_WITHDRAWAL', withdrawal.userId, { withdrawalId, reason })

    return updatedWithdrawal
  }

  /**
   * Admin: Get Withdrawals
   */
  static async getWithdrawals(status?: WithdrawalStatus, limit: number = 50) {
    const where = status ? { status } : {}
    return await prisma.withdrawal.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: limit,
      include: {
        user: { select: { name: true, email: true, kycStatus: true } },
      },
    })
  }

  /**
   * Admin: Bulk actions
   */
  static async processBulkWithdrawals(ids: string[], action: 'APPROVE' | 'REJECT', adminId: string, reason?: string) {
    const results = { success: 0, failed: 0, errors: [] as string[] }
    for (const id of ids) {
      try {
        if (action === 'APPROVE') await this.approveWithdrawal(id, adminId, reason)
        else await this.rejectWithdrawal(id, adminId, reason || 'Bulk rejection')
        results.success++
      } catch (e) {
        results.failed++
        results.errors.push(`ID ${id}: ${e instanceof Error ? e.message : String(e)}`)
      }
    }
    return results
  }

  /**
   * User: Withdrawal History
   */
  static async getWithdrawalHistory(userId: string) {
    return await prisma.withdrawal.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: 50,
    })
  }

  /**
   * User: Deposit History
   */
  static async getDepositHistory(userId: string) {
    return await prisma.deposit.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: 50,
    })
  }
}

import crypto from 'crypto'

export class ProvablyFairService {
  /**
   * Generate a new Server Seed
   * This should be kept secret until the game is over (or seed is rotated)
   */
  static generateServerSeed(): string {
    return crypto.randomBytes(32).toString('hex')
  }

  /**
   * Generate a new Client Seed
   * Default client seed for new users
   */
  static generateClientSeed(): string {
    return crypto.randomBytes(8).toString('hex')
  }

  /**
   * Hash the Server Seed
   * This is what we show to the user *before* the game
   */
  static hashServerSeed(serverSeed: string): string {
    return crypto.createHash('sha256').update(serverSeed).digest('hex')
  }

  /**
   * Calculate HMAC_SHA256
   * core of provably fair: hmac(serverSeed, clientSeed:nonce)
   */
  static calculateHmac(serverSeed: string, clientSeed: string, nonce: number): string {
    const message = `${clientSeed}:${nonce}`
    return crypto.createHmac('sha256', serverSeed).update(message).digest('hex')
  }

  /**
   * Generate a uniform float 0..1 from HMAC
   */
  static generateOutcome(serverSeed: string, clientSeed: string, nonce: number): number {
    const hash = this.calculateHmac(serverSeed, clientSeed, nonce)
    const h = parseInt(hash.slice(0, 13), 16)
    const e = Math.pow(2, 52)
    return h / e
  }

  static outcomeToDice(outcome: number): number {
    // 0.00 to 100.00
    return Math.floor(outcome * 10001) / 100
  }

  static outcomeToCoinFlip(outcome: number): 'HEADS' | 'TAILS' {
    return Math.floor(outcome * 2) === 0 ? 'HEADS' : 'TAILS'
  }

  static outcomeToRoulette(outcome: number): number {
    return Math.floor(outcome * 37) // 0-36
  }

  static outcomeToCrashMultiplier(outcome: number): number {
    // Instant crash check (1% chance usually, or derived from hash)
    // For simplicity with float input, we follow standard formula:
    // M = 0.99 / (1 - X)
    const multiplier = 0.99 / (1 - outcome)
    return Math.max(1.00, Math.floor(multiplier * 100) / 100)
  }

  static outcomeToPlinko(serverSeed: string, clientSeed: string, nonce: number, rows: number): number {
    // Returns bucket index 0..rows
    const path = this.calculatePlinkoPath(serverSeed, clientSeed, nonce, rows)
    return path.reduce((a, b) => a + b, 0)
  }

  static outcomeToMines(serverSeed: string, clientSeed: string, nonce: number, mineCount: number): number[] {
    const hash = this.calculateHmac(serverSeed, clientSeed, nonce)

    // Create array 0..24
    const deck = Array.from({ length: 25 }, (_, i) => i)

    // Fisher-Yates shuffle using hash
    const seed = parseInt(hash.slice(0, 8), 16)

    // Simple seeded shuffle
    // In production, use more of the hash bytes for better distribution
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor((seed / (i + 1)) % (i + 1))
      // XOR swap to mix it up or recalculate seed?
      // Let's just use standard PRNG logic with seed
      // Re-hashing is better.
      // For this demo:
      const h2 = parseInt(this.calculateHmac(serverSeed, clientSeed, nonce + i), 16)
      const swapIdx = h2 % (i + 1)
        ;[deck[i], deck[swapIdx]] = [deck[swapIdx], deck[i]]
    }

    return deck.slice(0, mineCount)
  }

  static outcomeToSlots(serverSeed: string, clientSeed: string, nonce: number): number[] {
    const hash = this.calculateHmac(serverSeed, clientSeed, nonce)
    // 3 reels, symbols 0-9
    const r1 = parseInt(hash.slice(0, 2), 16) % 10
    const r2 = parseInt(hash.slice(2, 4), 16) % 10
    const r3 = parseInt(hash.slice(4, 6), 16) % 10
    return [r1, r2, r3]
  }

  /**
   * Verify an outcome against a hash
   */
  static verifyOutcome(serverSeed: string, clientSeed: string, nonce: number, outcome: number): boolean {
    // Re-calculate based on what we expect 'outcome' to be. 
    // This depends on the game. 
    // If outcome is the float 0-1:
    const generated = this.generateOutcome(serverSeed, clientSeed, nonce)
    return Math.abs(generated - outcome) < 0.000001
  }

  /**
   * Crash Point Calculation (Original)
   * Kept for reference or backward compatibility
   */
  static calculateCrashPoint(serverSeed: string, clientSeed: string, nonce: number): number {
    const hash = this.calculateHmac(serverSeed, clientSeed, nonce)
    const h = parseInt(hash.slice(0, 13), 16)
    const e = Math.pow(2, 52)
    if (h % 33 === 0) return 1.00
    const result = Math.floor((100 * e - h) / (e - h)) / 100
    return Math.max(1.00, result)
  }

  /**
   * Plinko Path Calculation (Original)
   */
  static calculatePlinkoPath(serverSeed: string, clientSeed: string, nonce: number, rows: number): number[] {
    const hash = this.calculateHmac(serverSeed, clientSeed, nonce)

    // We need 'rows' number of bits/decisions
    // We can just use the hex string, convert to binary, or take groups

    const path: number[] = []

    // Simple implementation: 
    // Take chunks of hex characters, convert to int, mod 2
    // If we need more randomness than one hash provides, we might need to expand.
    // SHA256 is 256 bits. 16 rows needs 16 bits. Plenty.

    // Let's convert hash to a sequence of integers
    // We can take pairs of hex chars (1 byte) -> 0-255 -> mod 2?
    // Determine direction for each row

    for (let i = 0; i < rows; i++) {
      // Use 2 hex chars per row (0-255)
      // i*2 because 2 chars per byte
      const sub = hash.slice(i * 2, (i * 2) + 2)
      const val = parseInt(sub, 16)

      // 0 = Left, 1 = Right
      // 0.5 probability?
      const direction = val % 2 === 0 ? 0 : 1
      path.push(direction)
    }

    return path
  }
}
